1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  items: Item[];
14	}
15	
16	export interface QuoteResult {
17	  premium: number;
18	}
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	};
25	const PROCESSING_FEE = 5;
26	
27	// First-insurance surcharge of +10%, expressed as a numerator/denominator pair
28	// so the maths stays in integers: `base * 110 / 100` avoids the float error of
29	// `base * 1.1` (e.g. 100 * 1.1 === 100.00000000000001).
30	const FIRST_INSURANCE_SURCHARGE_NUMERATOR = 110;
31	const FIRST_INSURANCE_SURCHARGE_DENOMINATOR = 100;
32	
33	const sumBasePremiums = (items: Item[]): number =>
34	  items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
35	
36	export const quote = (
37	  _customer: Customer,
38	  step: QuoteStep,
39	  _quoteIndex: number,
40	): QuoteResult => {
41	  const basePremium = sumBasePremiums(step.items);
42	  const withFirstInsurance =
43	    (basePremium * FIRST_INSURANCE_SURCHARGE_NUMERATOR) /
44	    FIRST_INSURANCE_SURCHARGE_DENOMINATOR;
45	  const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
46	  return { premium };
47	};
